import{_ as a,o as t,c as s,a2 as o}from"./chunks/framework.D14Z5eOz.js";const u=JSON.parse('{"title":"Why sdd exists","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/why-sdd.md","filePath":"concepts/why-sdd.md","lastUpdated":1784865624000}'),i={name:"concepts/why-sdd.md"};function r(d,e,n,l,h,c){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="why-sdd-exists" tabindex="-1">Why sdd exists <a class="header-anchor" href="#why-sdd-exists" aria-label="Permalink to &quot;Why sdd exists&quot;">​</a></h1><blockquote><p>A local Spec-Driven Development CLI that pairs with AI coding agents — portable process without cloud SDD or IDE lock-in.</p></blockquote><p>Agents need a process spine; humans need it light enough to keep. Unstructured chat loses decisions; enterprise gates block solos.</p><p>Spec Kit–style init (<code>--ai grok|copilot|claude</code>), YAML stages, and markdown artifacts give a middle path: progressive structure (hotfix stays short; feature and enterprise can go deeper), all on your laptop.</p><p><code>sdd</code> is the spine. The agent is the writer.</p><h2 id="the-pain-it-addresses" tabindex="-1">The pain it addresses <a class="header-anchor" href="#the-pain-it-addresses" aria-label="Permalink to &quot;The pain it addresses&quot;">​</a></h2><p>Vibe coding ships fast and forgets <em>why</em>. Heavy SDD ships slowly and frustrates. <code>sdd</code> keeps change packs, local verify, and complete — same tool from a weekend project to a multi-team enterprise change with ARB gates, with agents reading one protocol and live context.</p><h2 id="what-we-are-not" tabindex="-1">What we are not <a class="header-anchor" href="#what-we-are-not" aria-label="Permalink to &quot;What we are not&quot;">​</a></h2><ul><li>Not a required IDE extension</li><li>Not a hosted collaboration suite</li><li>Not “skills packs” replacing a single playbook</li><li>Not mandatory archive or evidence folders (opt-in only)</li></ul><p>Try the <a href="./../tutorials/first-change">first-change tutorial</a>, <a href="./../guides/simple-feature">simple feature</a>, or <a href="./../guides/enterprise">enterprise path</a>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./change-packs">Change packs &amp; memory</a></li><li><a href="./agents-vs-ides">Agents vs IDEs</a></li></ul>',12)])])}const f=a(i,[["render",r]]);export{u as __pageData,f as default};
